import{_ as t,o as e,c as o,Q as i}from"./chunks/framework.c4d6cd72.js";const p=JSON.parse('{"title":"Contributions","description":"","frontmatter":{},"headers":[],"relativePath":"overview/contributions.md","filePath":"overview/contributions.md"}'),d={name:"overview/contributions.md"},r=i('<h1 id="contributions" tabindex="-1">Contributions <a class="header-anchor" href="#contributions" aria-label="Permalink to &quot;Contributions&quot;">​</a></h1><blockquote><p><strong>Contribution</strong> — a piece of data that describes a fraud event on the blockchain.</p></blockquote><p>Contributions can be submitted by authorized peers, and are stored on the blockchain.</p><p>A peer that has contributed at least a single fraud event is considered a <strong><em>contributor</em></strong>.</p><h2 id="operations" tabindex="-1">Operations <a class="header-anchor" href="#operations" aria-label="Permalink to &quot;Operations&quot;">​</a></h2><h3 id="submitting-contributions" tabindex="-1">Submitting contributions <a class="header-anchor" href="#submitting-contributions" aria-label="Permalink to &quot;Submitting contributions&quot;">​</a></h3><p>Once a contribution has been submitted, the peer’s list of contributions is updated, and their credit balance is increased by an amount equal to the number of contributions submitted based on the current reward rate active in the network.</p><p>For complete instructions on how to submit a contribution, see <a href="./../tutorials-api/submitting-a-contribution.html">Submitting a contribution</a>.</p><p>For information on the credit balance and rewards, see <a href="./tokenomics.html">Tokenomics</a>.</p><h3 id="retrieving-contributions" tabindex="-1">Retrieving contributions <a class="header-anchor" href="#retrieving-contributions" aria-label="Permalink to &quot;Retrieving contributions&quot;">​</a></h3><p>In order for peers to keep their own records updated with the latest fraud event data, they can <a href="./../tutorials-api/retrieving-top-contributions.html">retrieve top contributions in a number of ways</a>.</p><h3 id="flagging-contributions" tabindex="-1">Flagging contributions <a class="header-anchor" href="#flagging-contributions" aria-label="Permalink to &quot;Flagging contributions&quot;">​</a></h3><p>If a peer deems a certain contribution to no longer be relevant (e.g., <em>it is a false positive</em>), they can <a href="./../tutorials-api/flagging-a-contribution.html">flag that contribution</a>. Once a contribution is flagged, the ID of the peer that flagged it is saved with the contribution as <code>flagger</code> value.</p><h2 id="api-requests-data-structure" tabindex="-1">API requests data structure <a class="header-anchor" href="#api-requests-data-structure" aria-label="Permalink to &quot;API requests data structure&quot;">​</a></h2><p>When <a href="./../api-specification/contribution-controller/retrieving-top-contributions.html">retrieving top contributions</a>, the following data is returned in the body of the response:</p><details class="details custom-block"><summary>Response body</summary><table><thead><tr><th>Field</th><th>Value Type</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>string</code></td><td>Fraud event identifier.</td></tr><tr><td><code>fraudType</code></td><td><code>enum string</code></td><td>The type of the fraud event. <br> Could be one of the following: <ol><li><code>Wangiri</code></li><li><code>IRSF</code></li><li><code>StolenDevice</code></li><li><code>IPFraud</code></li><li><code>SMSA2P</code></li></ol></td></tr><tr><td><code>origination</code></td><td><code>string</code></td><td>The two-digit code of the country the fraud event originated from (Alpha-2, ISO 3166).</td></tr><tr><td><code>destination</code></td><td><code>string</code></td><td>The two-digit code of the country the fraud event was identified as such (Alpha-2, ISO 3166).</td></tr><tr><td><code>expiryDate</code></td><td><code>integer($int32)</code></td><td>The exact time and date until which the event is considered relevant (represented as <a href="https://www.epochconverter.com/clock" target="_blank" rel="noreferrer">Unix Epoch time</a> in seconds).</td></tr><tr><td><code>fraudStatus</code></td><td><code>enum string</code></td><td>The status of the event at the time of observing. <br> Could be one of the following: <ol><li><code>Active</code></li><li><code>Expired</code></li><li><code>Flagged</code></li></ol></td></tr><tr><td><code>confidenceIndex</code></td><td><code>number($double)</code></td><td>The predicted fraud likelihood score in the range from 1 to 100.</td></tr><tr><td><code>isPremium</code></td><td><code>boolean</code></td><td>The definition of whether the contributor is a premium user.</td></tr><tr><td><code>peerId</code></td><td><code>string</code></td><td>The unique ID of the peer that contributed the data.</td></tr><tr><td><code>flagger</code></td><td><code>string</code></td><td>The unique ID of the peer that flagged the data. If a contribution hasn&#39;t been flagged at the time of observing, the field is returned empty.</td></tr><tr><td><code>self</code></td><td><code>integer($int32)</code></td><td>Out of all the retrieved contributions, the number of contributions that have been submitted by the requesting user.</td></tr><tr><td><code>old</code></td><td><code>integer($int32)</code></td><td>Out of all the retrieved contributions, the number of contributions that have already been seen by the requesting user.</td></tr><tr><td><code>new</code></td><td><code>integer($int32)</code></td><td>Out of all the retrieved contributions, the number of contributions that have <em>not</em> yet been seen by the requesting user.</td></tr><tr><td><code>creditsSpent</code></td><td><code>integer($int32)</code></td><td>The total amount of credits spent on the retrieved contributions.</td></tr></tbody></table></details><p>When <a href="./../api-specification/contribution-controller/assembling-a-contribution.html">assembling a contribution</a> to then <a href="./../api-specification/contribution-controller/submitting-a-contribution.html">submit it</a>, the following data must be specified in the body of the request:</p><details class="details custom-block"><summary>Request body</summary><table><thead><tr><th>Field</th><th>Value Type</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td><code>string</code></td><td>Fraud event identifier.</td></tr><tr><td><code>fraudType</code></td><td><code>enum string</code></td><td>The type of the fraud event. <br> Could be one of the following: <ol><li><code>Wangiri</code></li><li><code>IRSF</code></li><li><code>StolenDevice</code></li><li><code>IPFraud</code></li><li><code>SMSA2P</code></li></ol></td></tr><tr><td><code>origination</code></td><td><code>string</code></td><td>The two-digit code of the country the fraud event originated from (Alpha-2, ISO 3166).</td></tr><tr><td><code>destination</code></td><td><code>string</code></td><td>The two-digit code of the country the fraud event was identified as such (Alpha-2, ISO 3166).</td></tr><tr><td><code>expiryDate</code></td><td><code>integer($int32)</code></td><td>The exact time and date until which the event is considered relevant (represented as <a href="https://www.epochconverter.com/clock" target="_blank" rel="noreferrer">Unix Epoch time</a> in seconds).</td></tr></tbody></table></details>',18),n=[r];function a(c,s,h,u,l,b){return e(),o("div",null,n)}const g=t(d,[["render",a]]);export{p as __pageData,g as default};
